#include<bits/stdc++.h>
#define ll long long
#define CI const int
#define PII pair<int,int>
#define mk(x,y) meke_pair(x,y);
#define inf 0x3f3f3f3f
using namespace std;
inline int read(){
    int x=0,f=1;
    char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
    while(ch>='0'&&ch<='9')x=x*10+ch-'0',ch=getchar();
    return x*f;
}
void write(int x){
    if(x<0)putchar('-'),x=-x;
    if(x>9)write(x/10);
    putchar(x%10+'0');return;
}
CI MAXN=1e5+5;
ll n,a[MAXN],cnt[MAXN],ans;
int main(){
    cin>>n;
    for(int i=1;i<=n;++i)
    {
        cin>>a[i];
    }
    sort(a+1,a+n+1);
    for(int i=1;i<=n;++i)
    {
        int j=i+1,flag=0;
        while(j<=n)
        {
            if(a[j]/2-cnt[j]>=a[i])
            {
                cnt[j]+=a[i];
                flag=1;
                break;
            }
            ++j;
        }
        if(!flag)++ans;
    }
    cout<<ans;
    return false;
}
